package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;
import java.math.BigInteger;

public class JsonPrimitiveTest {

  @Test
  void testIsIntegral_withBigInteger() throws Exception {
    JsonPrimitive primitive = Mockito.mock(JsonPrimitive.class, Mockito.withSettings()
        .useConstructor()
        .defaultAnswer(Mockito.CALLS_REAL_METHODS));
    // Use reflection to set private final field 'value' to BigInteger instance
    java.lang.reflect.Field valueField = JsonPrimitive.class.getDeclaredField("value");
    valueField.setAccessible(true);
    valueField.set(primitive, BigInteger.ONE);

    Method isIntegral = JsonPrimitive.class.getDeclaredMethod("isIntegral", JsonPrimitive.class);
    isIntegral.setAccessible(true);

    boolean result = (boolean) isIntegral.invoke(null, primitive);
    assertTrue(result);
  }

